        <div class="grid grid-cols-1 font-semibold text-xl mt-[86px] ml-4">
            <div class="flex">Gas Price: 
                <div class="flex ml-4 text-lg font-medium">
                    @if ($invoices->priceG != null) {{number_format((float)$invoices->priceG, 2)}} €/mc @else - @endif
                </div>
            </div>
            <div class="flex mt-3.5">Electricity Price: 
                <div class="flex ml-4 text-lg font-medium">
                    @if ($invoices->priceE != null) {{number_format((float)$invoices->priceE, 2)}} €/KW @else - @endif
                </div>
            </div>
            <div class="flex mt-3.5">Available Power: 
                <div class="flex ml-4 text-lg font-medium">
                    @if ($invoices->KWh != null) {{$invoices->KWh}} KW/h @else - @endif
                </div>
            </div>
        </div>
    </div>

    <div class="absolute top-[63.95rem] w-[29rem] h-[14.2rem] left-[37.05rem] bg-none">
        <div class="absolute top-[1.1rem] left-[18rem] text-xl font-semibold text-white">Profile Info</div>

        <div class="grid grid-cols-1 font-semibold text-xl mt-6 ml-4">
            @if (Auth::user()->PIVA == null)
            <div class="flex mt-10"></div>
            @endif
            <div class="flex">Type: 
                <div class="flex ml-4 text-lg font-medium">
                    @if (Auth::user()->PIVA != null) Business @else Private @endif
                </div>
            </div>
            <div class="flex mt-3.5">CF: 
                <div class="flex ml-4 text-lg font-medium">
                    {{Auth::user()->CF}}
                </div>
            </div>
            <div class="flex mt-3.5">Mail: 
                <div class="flex ml-4 text-lg font-medium">
                    {{Auth::user()->email}}
                </div>
            </div>
            <div class="flex mt-3.5">Phone: 
                <div class="flex ml-4 text-lg font-medium">
                    {{Auth::user()->phoneNumber}}
                </div>
            </div>
            @if (Auth::user()->PIVA != null)
            <div class="flex mt-3.5">P. IVA: 
                <div class="flex ml-4 text-lg font-medium">
                    {{Auth::user()->PIVA}}
                </div>
            </div>
            @endif
        </div>
    </div>

    <div class="absolute top-[79.85rem] w-[31.1rem] h-[10.15rem] left-[3.85rem] bg-none">
    <div class="absolute top-[0.9rem] left-[10.3rem] text-xl font-semibold text-white">Other Information</div>

        <div class="grid grid-cols-1 font-semibold text-lg mt-[68px] ml-4">
            <div class="flex">Our Website: 
                <div class="flex ml-6 text-md font-medium">
                    www.caerusenergy.com
                </div>
            </div>
            <div class="flex mt-1">Supporter Email: 
                <div class="flex ml-6 text-md font-medium">
                    caerusenergy@gmail.com
                </div>
            </div>
            <div class="flex mt-1">Supplier Email: 
                <div class="flex ml-6 text-md font-medium">
                    {{$invoices->email}}
                </div>
            </div>
        </div>
    </div>

    <div class="absolute top-[79.85rem] w-[29rem] h-[10.15rem] left-[37.05rem] grid grid-cols-1 content-center text-justify text-[10px]">
        <div class="mt-0.5 w-full text-gray-800">
            We kindly remind you that late payments may incur additional charges as outlined in our terms of service. 
            To avoid any inconvenience, please ensure timely settlement of your invoice.
        </div>
        <div class="mt-1.5 w-full text-gray-800">
            Please review the attached invoice for any specific clauses or terms relevant to your agreement with us. 
            If you have any questions or require clarification on any clause mentioned, feel free to reach out to our dedicated support team.
        </div>
        <div class="mt-1.5 w-full text-gray-800">
            Please note that unless specified otherwise in your agreement, your contract will automatically renew upon expiration.
        </div>
        <div class="mt-1.5 w-full text-gray-800">
            You can dismiss your contract at any time through our website's dedicated portal.
        </div>
    </div>

    <!-- Non bisogna assolutamente cancellare la seguente div, si storpia tutto -->
    <div class="absolute top-[84.55rem] w-[31.2rem] h-[11.15rem] left-[39.05rem] bg-none">
    </div>
</body>

<script>
  var options = {
  chart: {
    type: 'pie',
    animations: {
      enabled: false
    },
    height: '100%'
  },
  colors:['#009ddf', '#00d5e1', '#ffbb00', '#ff5f85', '#5c54c7'],
  series: [@if ($invoices->totGas != null) {{$invoices->totGas}} @else 0 @endif, @if ($invoices->totEle != null) {{$invoices->totEle}} @else 0 @endif, {{$invoices->transport}}, {{$invoices->meter}}, {{$invoices->IVA}}],
  dataLabels: {
      enabled: true,
      formatter: function (val) {
        return val.toFixed(1) + "%"
      }
    },
  legend: {
    show: false
  }
}

var chart = new ApexCharts(document.querySelector("#chart"), options);

chart.render();
</script>